#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long x,y,z; scanf("%lld %lld %lld",&x,&y,&z);
        long long arr[3]={x,y,z};
        int found=0; long long A,B;
        for(int i=0;i<3;i++){
            B=arr[i];
            A=arr[(i+1)%3]*arr[(i+2)%3];
            if(A % B == 0){
                printf("%lld %lld\n",A,B);
                found=1; break;
            }
        }
        if(!found) printf("-1\n");
    }
    return 0;
}

